CREATE TRIGGER [dbo].[OrderItem_History]ON [dbo].[OrderItem]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemId IS NOT NULL AND d.OrderItemId IS NULL THEN 'I' 		WHEN i.OrderItemId IS NOT NULL AND d.OrderItemId IS NOT NULL THEN 'U' 		WHEN i.OrderItemId IS NULL AND d.OrderItemId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemId = d.OrderItemId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItem([OrderItemId], [OrderId], [FinishedPartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemId], [OrderId], [FinishedPartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItem([OrderItemId], [OrderId], [FinishedPartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemId], [OrderId], [FinishedPartId], [Quantity], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND